24	pub(super) struct Vtable {
25	    /// Polls the future.
26	    pub(super) poll: unsafe fn(NonNull<Header>),
27	
28	    /// Schedules the task for execution on the runtime.
29	    pub(super) schedule: unsafe fn(NonNull<Header>),
